Class ListMerger Extends %RegisteredObject
{
    /// Merge two lists without duplicates
    ClassMethod MergeLists(list1 As %ListOfDataTypes, list2 As %ListOfDataTypes) As %ListOfDataTypes
    {
        Set result = ##class(%ListOfDataTypes).%New()

        // Add all from list1
        For i=1:1:list1.Count() {
            Do result.Insert(list1.GetAt(i))
        }

        // BUGGY: Adds all from list2 without checking for duplicates
        For i=1:1:list2.Count() {
            Do result.Insert(list2.GetAt(i))
        }

        Quit result
    }
}

