Class TestListMerger Extends %RegisteredObject
{
    ClassMethod TestMergeLists()
    {
        Set list1 = ##class(%ListOfDataTypes).%New()
        Do list1.Insert("apple")
        Do list1.Insert("banana")

        Set list2 = ##class(%ListOfDataTypes).%New()
        Do list2.Insert("banana")
        Do list2.Insert("cherry")

        Set merged = ##class(ListMerger).MergeLists(list1, list2)

        // Should have 3 unique items, not 4
        If (merged.Count() '= 3) {
            Throw ##class(%Exception.General).%New("Merged should have 3 items, got "_merged.Count())
        }

        // Count bananas - should be exactly 1
        Set bananaCount = 0
        For i=1:1:merged.Count() {
            If (merged.GetAt(i) = "banana") Set bananaCount = bananaCount + 1
        }
        If (bananaCount '= 1) {
            Throw ##class(%Exception.General).%New("Should have 1 banana, got "_bananaCount)
        }
    }
}
